import java.io.*;

public class SerializationDemo {

    static class User implements Serializable {
        private static final long serialVersionUID = 1L;

        private String username;
        private String email;
        private transient String passwordHash; // not serialized
        private transient int cachedHashCode;  // derived, skip

        public User(String username, String email, String passwordHash) {
            this.username = username;
            this.email = email;
            this.passwordHash = passwordHash;
        }

        // readObject: called after deserialization — reinitialize transient fields
        private void readObject(ObjectInputStream ois) throws IOException, ClassNotFoundException {
            ois.defaultReadObject(); // deserialize non-transient fields
            this.cachedHashCode = username.hashCode(); // recompute derived field
            // passwordHash stays null — must be re-fetched from DB
        }

        @Override public String toString() {
            return "User{username='" + username + "', email='" + email +
                   "', password=" + (passwordHash == null ? "null(transient)" : "***") + "}";
        }
    }

    public static void main(String[] args) throws Exception {
        User user = new User("alice", "alice@example.com", "$2a$12$hash");
        System.out.println("Before: " + user);

        // Serialize to byte array
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        try (ObjectOutputStream oos = new ObjectOutputStream(bos)) {
            oos.writeObject(user);
        }
        byte[] bytes = bos.toByteArray();
        System.out.println("Serialized size: " + bytes.length + " bytes");

        // Deserialize
        try (ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(bytes))) {
            User restored = (User) ois.readObject();
            System.out.println("After: " + restored); // password = null
        }
    }
}

import java.io.*;

public class ExternalizableDemo {

    static class Product implements Externalizable {
        private String sku;
        private double price;
        private int stock;
        private String description; // skip — too large, not needed remotely

        // REQUIRED: public no-arg constructor (Externalizable calls this before readExternal)
        public Product() {}

        public Product(String sku, double price, int stock, String description) {
            this.sku = sku; this.price = price;
            this.stock = stock; this.description = description;
        }

        @Override
        public void writeExternal(ObjectOutput out) throws IOException {
            out.writeUTF(sku);          // write only what's needed
            out.writeDouble(price);
            out.writeInt(stock);
            // description intentionally omitted
        }

        @Override
        public void readExternal(ObjectInput in) throws IOException {
            this.sku = in.readUTF();
            this.price = in.readDouble();
            this.stock = in.readInt();
            // description stays null
        }

        @Override public String toString() {
            return String.format("Product{sku='%s', price=%.2f, stock=%d, desc=%s}",
                sku, price, stock, description);
        }
    }

    // Singleton pattern with readResolve
    static class Config implements Serializable {
        private static final long serialVersionUID = 1L;
        private static final Config INSTANCE = new Config();
        private String env = "production";

        private Config() {}
        public static Config getInstance() { return INSTANCE; }

        // Prevent new instance on deserialization
        protected Object readResolve() { return INSTANCE; }
    }

    public static void main(String[] args) throws Exception {
        Product p = new Product("SKU-001", 29.99, 100, "A very long description...");
        System.out.println("Before: " + p);

        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        try (ObjectOutputStream oos = new ObjectOutputStream(bos)) {
            oos.writeObject(p);
        }

        try (ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(bos.toByteArray()))) {
            Product restored = (Product) ois.readObject();
            System.out.println("After: " + restored); // description=null
        }

        // Singleton safety
        Config c1 = Config.getInstance();
        ByteArrayOutputStream bos2 = new ByteArrayOutputStream();
        new ObjectOutputStream(bos2).writeObject(c1);
        Config c2 = (Config) new ObjectInputStream(new ByteArrayInputStream(bos2.toByteArray())).readObject();
        System.out.println("Same instance? " + (c1 == c2)); // true — readResolve
    }
}

