import java.io.*;
import java.sql.Connection;
import java.util.logging.Logger;

public class Q1 {
    static class OrderService implements Serializable {
        private static final long serialVersionUID = 1L; // fixed version
        private String orderId;
        private transient Logger log;          // not serializable
        private transient Connection dbConn;   // not serializable
        private int version;

        private void readObject(ObjectInputStream ois) throws IOException, ClassNotFoundException {
            ois.defaultReadObject();
            this.log = Logger.getLogger("orders"); // reinitialize transient
        }
    }

    public static void main(String[] args) throws Exception {
        OrderService svc = new OrderService();
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        new ObjectOutputStream(bos).writeObject(svc);
        OrderService restored = (OrderService) new ObjectInputStream(
            new ByteArrayInputStream(bos.toByteArray())).readObject();
        System.out.println("OK");
    }
}

