problems.solutionCode:
import java.io.*;
import java.util.*;

public class Q2 {
    @SuppressWarnings("unchecked")
    public static <T extends Serializable> T deepClone(T obj) throws Exception {
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        try (ObjectOutputStream oos = new ObjectOutputStream(bos)) {
            oos.writeObject(obj);
        }
        try (ObjectInputStream ois = new ObjectInputStream(
                new ByteArrayInputStream(bos.toByteArray()))) {
            return (T) ois.readObject();
        }
    }

    public static void main(String[] args) throws Exception {
        List<String> original = new ArrayList<>(Arrays.asList("a", "b", "c"));
        @SuppressWarnings("unchecked")
        List<String> clone = (List<String>) deepClone((Serializable) original);
        clone.add("d");
        System.out.println("Original: " + original); // [a, b, c]
        System.out.println("Clone:    " + clone);     // [a, b, c, d]
    }
}

