import java.io.*;

public class Q3 {
    static class Point3D implements Externalizable {
        double x, y, z;
        String label;

        public Point3D() {} // required by Externalizable

        @Override
        public void writeExternal(ObjectOutput out) throws IOException {
            out.writeDouble(x);
            out.writeDouble(y);
            out.writeDouble(z);
            // label intentionally not written
        }

        @Override
        public void readExternal(ObjectInput in) throws IOException {
            this.x = in.readDouble();
            this.y = in.readDouble();
            this.z = in.readDouble();
            // label stays null
        }
    }

    public static void main(String[] args) throws Exception {
        Point3D p = new Point3D();
        p.x = 1.5; p.y = 2.5; p.z = 3.5; p.label = "origin";

        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        new ObjectOutputStream(bos).writeObject(p);

        Point3D restored = (Point3D) new ObjectInputStream(
            new ByteArrayInputStream(bos.toByteArray())).readObject();

        System.out.println(restored.x + "," + restored.y + "," + restored.z);
        System.out.println(restored.label);
    }
}
